}

// С sealed class (отлично!)
sealed class UserState {
    object Loading : UserState()
    data class Success(val users: List<User>) : UserState()
    data class Error(val message: String) : UserState()
    object Empty : UserState()
}

// Использование в ViewModel
class UserViewModel : ViewModel() {
    private val _state = MutableStateFlow<UserState>(UserState.Loading)
    val state: StateFlow<UserState> = _state

    fun loadUsers() {
        viewModelScope.launch {
            _state.value = UserState.Loading
            try {
                val users = repository.getUsers()
                _state.value = if (users.isEmpty()) {
                    UserState.Empty
                } else {
                    UserState.Success(users)
                }
            } catch (e: Exception) {
                _state.value = UserState.Error(e.message ?: "Unknown error")
            }
        }
    }
}

@Composable
fun UserScreen(viewModel: UserViewModel) {
    val state by viewModel.state.collectAsState()

    when (state) {
        is UserState.Loading -> LoadingScreen()
        is UserState.Success -> UserList(users = (state as UserState.Success).users)
        is UserState.Error -> ErrorScreen(message = (state as UserState.Error).message)
        UserState.Empty -> EmptyScreen()
        // Компилятор проверяет, что все cases обработаны!
    }
}

// Smart cast работает автоматически!
@Composable
fun UserScreenBetter(viewModel: UserViewModel) {
    val state by viewModel.state.collectAsState()

    when (state) {
        UserState.Loading -> LoadingScreen()
        is UserState.Success -> {
            // Smart cast: state автоматически становится UserState.Success
            UserList(users = state.users)
        }
        is UserState.Error -> {
            ErrorScreen(message = state.message)
        }
        UserState.Empty -> EmptyScreen()
    }
}
